import { ChangeDetectionStrategy, Component, OnInit, computed, signal } from '@angular/core';
import { AdminService } from '../../../services/admin.service';
import { MessagingService } from '../../../services/messaging.service';
import { CompassConfiguration } from '../../../models/compass-configuration.model';
import { filterLocationsInScope, Subroute } from './location-config.helpers';

@Component({
  selector: 'app-location-config',
  templateUrl: './location-config.component.html',
  styleUrls: ['./location-config.component.scss'],
  changeDetection: ChangeDetectionStrategy.OnPush
})
export class LocationConfigComponent implements OnInit {
  readonly workflowOptions = [{ value: 'PRIORAUTH', label: 'Prior Auth' }];
  readonly subrouteOptions: { value: Subroute; label: string }[] = [
    { value: 'incoming', label: 'Incoming' },
    { value: 'outgoing', label: 'Outgoing' }
  ];

  private _config = signal<CompassConfiguration | null>(null);
  private _originalConfig = signal<CompassConfiguration | null>(null);

  loading = signal(false);
  loadError = signal<string | null>(null);
  selectedWorkflow = signal<string>('PRIORAUTH');
  selectedSubroute = signal<Subroute>('incoming');

  readonly locationsInScope = computed(() => {
    const cfg = this._config();
    if (!cfg) return [];
    return filterLocationsInScope(cfg, this.selectedWorkflow(), 'prior-auth', this.selectedSubroute());
  });

  readonly inScopeCount = computed(() => this.locationsInScope().length);

  readonly lastSaved = computed(() => this._originalConfig()?.updtDtTm ?? null);

  constructor(
    private adminService: AdminService,
    private messaging: MessagingService
  ) {}

  ngOnInit(): void {
    this.loadConfig();
  }

  loadConfig(): void {
    this.loading.set(true);
    this.loadError.set(null);
    this.adminService.getCompassConfiguration().subscribe({
      next: (cfg: any) => {
        if (!cfg) {
          this.loadError.set('Configuration response was empty.');
          this.loading.set(false);
          return;
        }
        this._originalConfig.set(structuredClone(cfg));
        this._config.set(cfg as CompassConfiguration);
        this.loading.set(false);
      },
      error: (err: any) => {
        this.loadError.set(err?.message ?? 'Failed to load configuration.');
        this.loading.set(false);
      }
    });
  }

  onWorkflowChange(value: string): void {
    this.selectedWorkflow.set(value);
  }

  onSubrouteChange(value: Subroute): void {
    this.selectedSubroute.set(value);
  }
}
