import { Injectable } from '@angular/core';
import { Observable, of } from 'rxjs';
import { CustomService } from '@clinicaloffice/clinical-office-mpage-core';
import { FeedbackData } from '../compass-content/feedback-form/feedback-form.component';
import { MessagingService } from './messaging.service';

/**
 * Response structure returned by the feedback submission service
 * 
 * @interface FeedbackResponse
 * @property {boolean} success - Indicates whether the feedback was successfully submitted
 * @property {string} message - Human-readable message describing the result
 * @property {string} [feedbackId] - Optional unique identifier assigned to the submitted feedback
 */
export interface FeedbackResponse {
  success: boolean;
  message: string;
  feedbackId?: string;
}

/**
 * FeedbackService - User Feedback Management System
 * 
 * This service handles the collection, processing, and submission of user feedback
 * throughout the COMPASS application. It integrates with the Clinical Office 
 * CustomService to persist feedback data and provides real-time user notifications.
 * 
 * ARCHITECTURE:
 * - Built on Clinical Office's CustomService for Cerner EMR integration
 * - Uses Observable patterns for asynchronous feedback submission
 * - Integrates with MessagingService for user notification feedback
 * - Supports both specific item feedback and general application feedback
 * 
 * CLINICAL OFFICE INTEGRATION:
 * - Calls 'cov_compass_service' CCL script with 'submitFeedback' request type
 * - Passes feedback data as JSON-stringified parameters
 * - Processes standardized response format with status codes and messages
 * - Extracts feedback IDs from subeventstatus for tracking purposes
 * 
 * FEEDBACK FLOW:
 * 1. User submits feedback through FeedbackFormComponent modal
 * 2. Service packages feedback data with context (item ID, type, meaning)
 * 3. CustomService executes CCL script to persist feedback in Cerner database
 * 4. Service processes response and shows success/error message to user
 * 5. Returns feedback ID for potential follow-up or tracking
 * 
 * ERROR HANDLING:
 * - Gracefully handles CustomService failures
 * - Provides meaningful error messages to users via MessagingService
 * - Maintains application stability during backend communication issues
 * - Logs errors appropriately for debugging and monitoring
 * 
 * USAGE EXAMPLES:
 * ```typescript
 * // Submit feedback (see FeedbackData in feedback-form.component for full shape)
 * this.feedbackService.submitFeedback(feedbackData).subscribe({
 *   next: (response) => {
 *     if (response.success) {
 *       console.log('Feedback submitted with ID:', response.feedbackId);
 *     }
 *   },
 *   error: (error) => {
 *     console.error('Feedback submission failed:', error);
 *   }
 * });
 * ```
 *
 * DATA PERSISTENCE:
 * - Feedback is stored in Cerner database tables via CCL scripts
 * - Each feedback entry receives a unique identifier for tracking
 * - Associated with user context and timestamp for audit purposes
 * - Enables reporting and analysis of user feedback patterns
 */
@Injectable({
  providedIn: 'root'
})
export class FeedbackService {
  /**
   * Constructor for FeedbackService
   * 
   * @param customService - Clinical Office CustomService for CCL script execution
   * @param messagingService - MessagingService for user notifications
   */
  constructor(
    private customService: CustomService,
    private messagingService: MessagingService
  ) {}

  /**
   * Submit user feedback to the COMPASS feedback system
   * 
   * This method packages the feedback data and submits it via the Clinical Office
   * CustomService to the 'cov_compass_service' CCL script for persistence in the
   * Cerner EMR database. The method handles the complete feedback submission flow
   * including user notifications and error handling.
   * 
   * SUBMISSION PROCESS:
   * 1. Packages feedback data with contextual information
   * 2. Executes 'cov_compass_service' with 'submitFeedback' request type
   * 3. Processes response status and extracts feedback ID if available
   * 4. Shows success/error message to user via MessagingService
   * 5. Returns standardized response object with success status and details
   * 
   * ERROR SCENARIOS:
   * - Network failures during CustomService execution
   * - CCL script errors or database constraints
   * - Invalid feedback data format or missing required fields
   * - Authentication or authorization issues with Cerner services
   * 
   * @param feedbackData - Complete feedback information matching the FeedbackData
   *   interface declared in feedback-form.component.ts, including:
   *   - user / userName / submissionDateTime: submitter context
   *   - itemId / itemType / itemMeaning / itemReference: referenced item context
   *   - feedbackNarrative: user-entered feedback text
   *   - feedbackPriority: 'LOW' | 'MEDIUM' | 'HIGH' | 'CRITICAL'
   *   - workflowStatus: initial workflow status block
   *   - item: reference to the source PriorAuthItem (when applicable)
   *
   * @returns Observable<FeedbackResponse> - Emits response containing:
   *   - success: Boolean indicating submission success/failure
   *   - message: User-friendly status message
   *   - feedbackId: Optional unique identifier for the submitted feedback,
   *     extracted from subeventstatus[].targetobjectname === 'COMPASS ID'
   */
  submitFeedback(feedbackData: FeedbackData): Observable<FeedbackResponse> {
    // Prepare to submit feedback data to the cov_compass_service

    return new Observable<FeedbackResponse>(observer => {
      this.customService.load(
        {
          customScript: {
            script: [
              {
                name: 'cov_compass_service',
                run: 'pre', 
                id: 'submitFeedback',
                parameters: { 
                  requestType: 'submitFeedback',
                  feedbackId: feedbackData.itemId,
                  requestMeaning: feedbackData.itemMeaning,
                  feedbackData: JSON.stringify({
                    request_object: feedbackData
                  })
                }
              }
            ],
            clearPatientSource: true
          }
        },
        [{ personId: 0, encntrId: 0 }],
        () => {
          try {
            const response = this.customService.get('submitFeedback');
            // Process the response from the feedback submission service

            // Handle new response structure with 'reply' wrapper
            const replyData = response?.reply || response;
            
            if (replyData && replyData.statusData && replyData.statusData.status === 'S') {
              const successMessage = replyData.text || 'Feedback submitted successfully';
              this.messagingService.success(successMessage);
              
              // Extract feedback ID from CCL response for tracking and follow-up
              // The CCL script returns the assigned feedback ID in the subeventstatus array
              // under the targetobjectname 'COMPASS ID' for consistent identification
              let feedbackId: string | undefined;
              if (replyData.statusData.subeventstatus && replyData.statusData.subeventstatus.length > 0) {
                const compassIdEntry = replyData.statusData.subeventstatus.find(
                  (subevent: any) => subevent.targetobjectname?.trim() === 'COMPASS ID'
                );
                if (compassIdEntry) {
                  feedbackId = compassIdEntry.targetobjectvalue?.trim();
                }
              }
              
              observer.next({
                success: true,
                message: successMessage,
                feedbackId: feedbackId
              });
            } else {
              const errorMessage = replyData?.text || 'Failed to submit feedback';
              this.messagingService.error(errorMessage);
              observer.next({
                success: false,
                message: errorMessage
              });
            }
            observer.complete();
          } catch (error) {
            // Handle unexpected errors during feedback submission process
            const errorMessage = 'Error submitting feedback';
            this.messagingService.error(errorMessage);
            observer.next({
              success: false,
              message: errorMessage
            });
            observer.complete();
          }
        }
      );
    });
  }
} 