import { CompassConfiguration, ConfigurationMapping, FilterSet, Workflow } from '../../../models/compass-configuration.model';

export type Subroute = 'incoming' | 'outgoing';

function findWorkflow(config: CompassConfiguration, workflowMeaning: string): Workflow | undefined {
  return config.workflows?.find(w => w.meaning === workflowMeaning);
}

export function filterLocationsInScope(
  config: CompassConfiguration,
  workflowMeaning: string,
  route: string,
  subroute: Subroute
): FilterSet[] {
  const wf = findWorkflow(config, workflowMeaning);
  if (!wf) return [];
  const sets: FilterSet[] = (wf.filterSets ?? []).filter(fs =>
    fs.type === 'LocationOption' &&
    fs.route === route &&
    fs.subroute === subroute
  );
  return [...sets].sort((a, b) => {
    const so = (a.sortOrder ?? 0) - (b.sortOrder ?? 0);
    if (so !== 0) return so;
    return String(a.label ?? '').localeCompare(String(b.label ?? ''));
  });
}

export function isUniqueId(
  config: CompassConfiguration,
  workflowMeaning: string,
  route: string,
  subroute: Subroute,
  candidateId: string,
  currentId: string | null
): boolean {
  const lower = candidateId.toLowerCase();
  const sets = filterLocationsInScope(config, workflowMeaning, route, subroute);
  // Both the candidate match and the currentId exclusion use toLowerCase so that
  // mixed-case currentId values are correctly excluded (fix #2).
  return !sets.some(fs => fs.id.toLowerCase() === lower && fs.id.toLowerCase() !== currentId?.toLowerCase());
}

/**
 * Rewrites the `*Cnt` count fields on the config and its nested workflows to match
 * the actual array lengths. Mutates the config in place.
 */
export function normalizeCountFields(config: CompassConfiguration): void {
  if (Array.isArray(config.workflows)) {
    config.workflows.forEach(wf => {
      if (Array.isArray(wf.filterSets)) wf.filterSetsCnt = wf.filterSets.length;
      if (Array.isArray(wf.milestones)) wf.milestoneCnt = wf.milestones.length;
      if (Array.isArray(wf.dataElements)) wf.dataElementsCnt = wf.dataElements.length;
      if (Array.isArray(wf.itemHighlight)) wf.itemHighlightCnt = wf.itemHighlight.length;
    });
    config.workflowCnt = config.workflows.length;
  }
  if (Array.isArray(config.worklists)) config.worklistCnt = config.worklists.length;
  if (Array.isArray(config.mapping)) config.mappingCnt = config.mapping.length;
}

/**
 * Removes a mapping entry whose `keyRefValue` equals `mappingSource` when no other
 * LocationOption filter set (besides the one being removed) still references that
 * source value. Only LocationOption filter sets are checked because mappings are
 * exclusively paired with location options in this workflow. Mutates the config in place.
 */
export function cascadeMappingRemoval(
  config: CompassConfiguration,
  mappingSource: string,
  removedLocationId: string
): void {
  if (!Array.isArray(config.mapping)) return;
  const stillReferenced = (config.workflows ?? []).some(wf =>
    (wf.filterSets ?? []).some(fs =>
      fs.id !== removedLocationId &&
      fs.type === 'LocationOption' &&
      (fs.filters ?? []).some(f =>
        Array.isArray(f.options) &&
        // FilterSetOption is always { item: string } per the model
        f.options.some(opt => opt.item === mappingSource)
      )
    )
  );
  if (!stillReferenced) {
    // Use keyRefValue — the correct field on ConfigurationMapping (fix #1)
    config.mapping = config.mapping.filter((m: ConfigurationMapping) => m.keyRefValue !== mappingSource);
  }
}
