import {
  AfterViewInit,
  ChangeDetectionStrategy,
  Component,
  ElementRef,
  EventEmitter,
  Input,
  OnChanges,
  OnDestroy,
  Output,
  SimpleChanges,
  ViewChild
} from '@angular/core';
import { createJSONEditor, Mode, type Content, type JsonEditor, type OnChangeStatus } from 'vanilla-jsoneditor';

@Component({
  selector: 'app-vanilla-json-editor',
  templateUrl: './vanilla-json-editor.component.html',
  styleUrls: ['./vanilla-json-editor.component.scss'],
  changeDetection: ChangeDetectionStrategy.OnPush
})
export class VanillaJsonEditorComponent implements AfterViewInit, OnChanges, OnDestroy {
  @Input() json: unknown = {};
  @Input() readOnly = false;
  @Input() mode: 'text' | 'tree' = 'tree';

  @Output() jsonChange = new EventEmitter<unknown>();
  @Output() parseError = new EventEmitter<string | null>();

  @ViewChild('host', { static: true }) hostRef!: ElementRef<HTMLDivElement>;

  private editor: JsonEditor | null = null;
  private suppressNextEmit = false;

  ngAfterViewInit(): void {
    this.editor = createJSONEditor({
      target: this.hostRef.nativeElement,
      props: {
        content: { json: this.json } as Content,
        mode: this.mode === 'text' ? Mode.text : Mode.tree,
        readOnly: this.readOnly,
        onChange: (updated: Content, _previous: Content, status: OnChangeStatus) => {
          if (this.suppressNextEmit) {
            this.suppressNextEmit = false;
            return;
          }
          if (status.contentErrors) {
            this.parseError.emit('Invalid JSON');
            return;
          }
          this.parseError.emit(null);
          const next = 'json' in updated ? updated.json : safeParse((updated as { text?: string }).text);
          if (next !== undefined) this.jsonChange.emit(next);
        }
      }
    });
  }

  ngOnChanges(changes: SimpleChanges): void {
    if (!this.editor) return;
    if (changes['json'] && !changes['json'].firstChange) {
      this.suppressNextEmit = true;
      this.editor.update({ json: this.json } as Content);
    }
    if (changes['mode'] && !changes['mode'].firstChange) {
      this.editor.updateProps({ mode: this.mode === 'text' ? Mode.text : Mode.tree });
    }
    if (changes['readOnly'] && !changes['readOnly'].firstChange) {
      this.editor.updateProps({ readOnly: this.readOnly });
    }
  }

  ngOnDestroy(): void {
    this.editor?.destroy();
    this.editor = null;
  }
}

function safeParse(text: string | undefined): unknown {
  if (text === undefined) return undefined;
  try { return JSON.parse(text); } catch { return undefined; }
}
